                if (response.ok) {
                    loadProducts();
                    showMessage('✓ Xóa sản phẩm thành công');
                } else {
                    showMessage('❌ Lỗi khi xóa sản phẩm');
                }
            })
            .catch(error => {
                console.error('Error deleting product:', error);
                showMessage('❌ Lỗi khi xóa sản phẩm');
            });
        }
    }

    connection.on("ReceiveNotification", (notification) => {
        const typeIcon = {
            'Added': '✓ Thêm',
            'Updated': '✎ Cập nhật',
            'Deleted': '✕ Xóa'
        };
        const type = typeIcon[notification.notificationType] || notification.notificationType;
        showMessage(`${type}: ${notification.productName}`);
        loadProducts();
    });

    connection.start()
        .then(() => {
            console.log('✓ Kết nối ProductHub thành công');
            loadProducts();
        })
        .catch(err => {
            console.error('❌ Lỗi kết nối:', err);
            loadProducts();
        });
</script>

</body>
</html>
